int* productExceptSelf(int* nums, int n, int* rs) {
    int* ans = malloc(n * sizeof(int));
    int prefix = 1;
    for (int i = 0; i < n; i++) { ans[i] = prefix; prefix *= nums[i]; }
    int suffix = 1;
    for (int i = n - 1; i >= 0; i--) { ans[i] *= suffix; suffix *= nums[i]; }
    *rs = n;
    return ans;
}
